SELECT ar.id, ar.content_id AS contentId, ar.content_type AS contentType,
       ar.source_type AS sourceType,
       ar.content, ar.submitter_id AS submitterId,
       ar.auto_audit_result AS autoAuditResult, ar.manual_audit_result AS manualAuditResult,
       ar.auditor_id AS auditorId, ar.audit_time AS auditTime,
       ar.reject_reason AS rejectReason, ar.created_at AS createdAt,
       u.username AS submitterName
FROM audit_records ar
LEFT JOIN users u ON ar.submitter_id = u.id


        AND ar.content_type = #{contentType}


        AND ar.manual_audit_result = #{manualAuditResult}


        AND ar.source_type = #{sourceType}


        AND ar.created_at >= #{startDate}


        AND ar.created_at <= #{endDate}


ORDER BY ar.created_at DESC
LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM audit_records ar


        AND ar.content_type = #{contentType}


        AND ar.manual_audit_result = #{manualAuditResult}


        AND ar.source_type = #{sourceType}


        AND ar.created_at >= #{startDate}


        AND ar.created_at <= #{endDate}

mapper.update:
UPDATE audit_records
SET manual_audit_result = #{manualAuditResult},
    auditor_id = #{auditorId},
    audit_time = NOW(),
    reject_reason = #{rejectReason}
WHERE id = #{id}

UPDATE audit_records
SET auto_audit_result = #{manualAuditResult},
    reject_reason = #{rejectReason}
WHERE content_id = #{contentId}

mapper.select:
SELECT COUNT(*) AS totalCount, SUM(CASE WHEN manual_audit_result = 'approved' THEN 1 ELSE 0 END) AS approvedCount, SUM(CASE WHEN manual_audit_result = 'rejected' THEN 1 ELSE 0 END) AS rejectedCount, SUM(CASE WHEN manual_audit_result = 'pending' THEN 1 ELSE 0 END) AS pendingCount, SUM(CASE WHEN auto_audit_result = 'rejected' THEN 1 ELSE 0 END) AS autoRejectedCount FROM audit_records WHERE 1=1
AND created_at >= #{startDate}
AND created_at <= #{endDate}

SELECT au.username AS auditorName, ar.auditor_id AS auditorId, COUNT(*) AS auditCount, SUM(CASE WHEN ar.manual_audit_result = 'approved' THEN 1 ELSE 0 END) AS approvedCount, SUM(CASE WHEN ar.manual_audit_result = 'rejected' THEN 1 ELSE 0 END) AS rejectedCount FROM audit_records ar LEFT JOIN admin_users au ON ar.auditor_id = au.id WHERE ar.auditor_id IS NOT NULL
AND ar.audit_time >= #{startDate}
AND ar.audit_time <= #{endDate}
GROUP BY ar.auditor_id, au.username ORDER BY auditCount DESC

SELECT id, content_id AS contentId, content_type AS contentType, source_type AS sourceType,
       auto_audit_result AS autoAuditResult, manual_audit_result AS manualAuditResult
FROM audit_records WHERE id = #{id}

SELECT content_type AS contentType, COUNT(*) AS totalCount, SUM(CASE WHEN manual_audit_result = 'approved' THEN 1 ELSE 0 END) AS approvedCount, SUM(CASE WHEN manual_audit_result = 'rejected' THEN 1 ELSE 0 END) AS rejectedCount, SUM(CASE WHEN manual_audit_result = 'pending' THEN 1 ELSE 0 END) AS pendingCount FROM audit_records WHERE 1=1
AND created_at >= #{startDate}
AND created_at <= #{endDate}
GROUP BY content_type
